def _cc_schema():
    return json.loads(xget('https://raw.githubusercontent.com/canonical/cloud-init/main/cloudinit/config/schemas/versions.schema.cloud-config.json').text)

def cc_validate(d):
    validate(d, schema=_cc_schema())


